/**
 * Generated by `createservice subscription.ActivateSubscriptionContextService --type mutations`
 */

const { faker } = require('@faker-js/faker')
const dayjs = require('dayjs')

const { getById } = require('@open-condo/keystone/schema')
const { makeLoggedInAdminClient, makeClient, expectToThrowGQLError, waitFor } = require('@open-condo/keystone/test.utils')
const { expectToThrowAccessDeniedErrorToResult, expectToThrowAuthenticationErrorToResult } = require('@open-condo/keystone/test.utils')

const {
    updateTestMultiPayment,
    Payment,
} = require('@condo/domains/acquiring/utils/testSchema')
const { INVOICE_STATUS_PAID } = require('@condo/domains/marketplace/constants')
const { updateTestInvoice } = require('@condo/domains/marketplace/utils/testSchema')
const { MANAGING_COMPANY_TYPE } = require('@condo/domains/organization/constants/common')
const { registerNewOrganization } = require('@condo/domains/organization/utils/testSchema')
const { SUBSCRIPTION_PERIOD, SUBSCRIPTION_CONTEXT_STATUS } = require('@condo/domains/subscription/constants')
const {
    activateSubscriptionContextByTestClient,
    registerSubscriptionContextByTestClient,
    createTestSubscriptionPlan,
    createTestSubscriptionPlanPricingRule,
    createTestSubscriptionContext,
    ensureSubscriptionPaymentRecipientForTests,
} = require('@condo/domains/subscription/utils/testSchema')
const { makeClientWithNewRegisteredAndLoggedInUser, makeClientWithSupportUser } = require('@condo/domains/user/utils/testSchema')

const { ERRORS } = require('./ActivateSubscriptionContextService')

describe('ActivateSubscriptionContextService', () => {
    let admin, support, user, anonymous
    let organization, subscriptionPlan, pricingRule

    beforeAll(async () => {
        admin = await makeLoggedInAdminClient()
        support = await makeClientWithSupportUser()
        anonymous = await makeClient()

        await ensureSubscriptionPaymentRecipientForTests(admin)

        const [plan] = await createTestSubscriptionPlan(admin, {
            name: faker.commerce.productName(),
            organizationType: MANAGING_COMPANY_TYPE,
            isHidden: false,
            trialDays: 14,
        })
        subscriptionPlan = plan

        const [rule] = await createTestSubscriptionPlanPricingRule(admin, subscriptionPlan, {
            period: SUBSCRIPTION_PERIOD.MONTH,
            price: '1000.00',
            currencyCode: 'RUB',
        })
        pricingRule = rule
    })

    beforeEach(async () => {
        user = await makeClientWithNewRegisteredAndLoggedInUser()
        const [org] = await registerNewOrganization(user, { type: MANAGING_COMPANY_TYPE })
        organization = org
    })

    describe('Access', () => {
        test('admin can call activateSubscriptionContext without access denied error', async () => {
            const [result] = await registerSubscriptionContextByTestClient(admin, {
                organization: { id: organization.id },
                subscriptionPlanPricingRule: { id: pricingRule.id },
                isTrial: false,
            })
            
            await expectToThrowGQLError(async () => {
                await activateSubscriptionContextByTestClient(admin, result.subscriptionContext)
            }, ERRORS.INVOICE_NOT_PAID, 'result')
        })

        test('support can call activateSubscriptionContext without access denied error', async () => {
            const [result] = await registerSubscriptionContextByTestClient(admin, {
                organization: { id: organization.id },
                subscriptionPlanPricingRule: { id: pricingRule.id },
                isTrial: false,
            })
            
            await expectToThrowGQLError(async () => {
                await activateSubscriptionContextByTestClient(support, result.subscriptionContext)
            }, ERRORS.INVOICE_NOT_PAID, 'result')
        })

        test('regular user cannot activate subscription context', async () => {
            const [result] = await registerSubscriptionContextByTestClient(admin, {
                organization: { id: organization.id },
                subscriptionPlanPricingRule: { id: pricingRule.id },
                isTrial: false,
            })

            await expectToThrowAccessDeniedErrorToResult(async () => {
                await activateSubscriptionContextByTestClient(user, result.subscriptionContext)
            })
        })

        test('anonymous cannot activate', async () => {
            const [result] = await registerSubscriptionContextByTestClient(admin, {
                organization: { id: organization.id },
                subscriptionPlanPricingRule: { id: pricingRule.id },
                isTrial: false,
            })

            await expectToThrowAuthenticationErrorToResult(async () => {
                await activateSubscriptionContextByTestClient(anonymous, result.subscriptionContext)
            })
        })
    })

    describe('Validation Logic', () => {
        test('throws error if subscription context not found', async () => {
            const fakeContext = { id: '00000000-0000-0000-0000-000000000000' }

            await expectToThrowGQLError(async () => {
                await activateSubscriptionContextByTestClient(admin, fakeContext)
            }, ERRORS.SUBSCRIPTION_CONTEXT_NOT_FOUND, 'result')
        })

        test('throws error if subscription context has wrong status', async () => {
            const [context] = await createTestSubscriptionContext(admin, organization, subscriptionPlan, {
                startAt: dayjs().format('YYYY-MM-DD'),
                endAt: dayjs().add(1, 'month').format('YYYY-MM-DD'),
                isTrial: false,
                status: SUBSCRIPTION_CONTEXT_STATUS.DONE,
            })

            await expectToThrowGQLError(async () => {
                await activateSubscriptionContextByTestClient(admin, context)
            }, ERRORS.SUBSCRIPTION_CONTEXT_INVALID_STATUS, 'result')
        })

        test('throws error if invoice not found', async () => {
            const [context] = await createTestSubscriptionContext(admin, organization, subscriptionPlan, {
                startAt: dayjs().format('YYYY-MM-DD'),
                endAt: dayjs().add(1, 'month').format('YYYY-MM-DD'),
                isTrial: false,
                status: SUBSCRIPTION_CONTEXT_STATUS.CREATED,
            })

            await expectToThrowGQLError(async () => {
                await activateSubscriptionContextByTestClient(admin, context)
            }, ERRORS.INVOICE_NOT_FOUND, 'result')
        })
    })

    describe('Payment Method Extraction and Freezing', () => {
        test('extracts payment method from multiPayment and freezes payment info when transitioning to DONE', async () => {
            const [result] = await registerSubscriptionContextByTestClient(admin, {
                organization: { id: organization.id },
                subscriptionPlanPricingRule: { id: pricingRule.id },
                isTrial: false,
            })
            const subscriptionContext = result.subscriptionContext
            const invoice = result.subscriptionContext.invoice
            
            const [payment] = await Payment.getAll(admin, {
                invoice: { id: invoice.id },
                deletedAt: null,
            })
            
            const testPaymentMethod = {
                bindingId: faker.datatype.uuid(),
                paymentSystem: 'MasterCard',
                cardNumber: '******4242',
                expiration: '12/2025',
                bankName: 'Test Bank',
                bankCountryCode: 'RU',
            }
            await updateTestMultiPayment(admin, payment.multiPayment.id, {
                meta: { paymentMethod: testPaymentMethod },
            })
            
            await updateTestInvoice(admin, invoice.id, { status: INVOICE_STATUS_PAID })
            
            await waitFor(async () => {
                const updatedContext = await getById('SubscriptionContext', subscriptionContext.id)
                expect(updatedContext.status).toBe(SUBSCRIPTION_CONTEXT_STATUS.DONE)
            })
            
            const finalContext = await getById('SubscriptionContext', subscriptionContext.id)
            expect(finalContext.bindingId).toBe(testPaymentMethod.bindingId)
            expect(finalContext.bindingId).toBeDefined()
            
            expect(finalContext.frozenPaymentInfo).toBeDefined()
            expect(finalContext.frozenPaymentInfo.paymentMethod).toEqual(testPaymentMethod)
            expect(finalContext.frozenPaymentInfo.invoice).toBeDefined()
            expect(finalContext.frozenPaymentInfo.invoice.id).toBe(invoice.id)
            expect(finalContext.frozenPaymentInfo.invoice.toPay).toBe(invoice.toPay)
            expect(finalContext.frozenPaymentInfo.pricingRuleId).toBe(pricingRule.id)
            expect(finalContext.frozenPaymentInfo.multiPaymentId).toBeDefined()
        })
    })
})
